patches.diff:
--- /dev/null
+++ b/src/utils/pagination.ts
@@ -0,0 +1,8 @@
+export interface PaginationParams { offset: number; limit: number; }
+
+export function parsePagination(query: Record<string, string>): PaginationParams {
+  return {
+    offset: Math.max(0, parseInt(query.offset || '0', 10)),
+    limit: Math.min(100, Math.max(1, parseInt(query.limit || '20', 10))),
+  };
+}

--- a/src/routes/list.ts
+++ b/src/routes/list.ts
@@ -1,5 +1,7 @@
 import { Router } from 'express';
 import { getItems } from '../controllers/list';
+import { parsePagination } from '../utils/pagination';

 const router = Router();
-router.get('/list', async (req, res) => res.json(await getItems()));
+router.get('/list', async (req, res) => {
+  const { offset, limit } = parsePagination(req.query as Record<string, string>);
+  res.json(await getItems({ offset, limit }));
+});
